create table enum (
    id       number(*, 0)
        generated by default on null as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 start with 1 cache 20
        noorder nocycle nokeep noscale
    not null enable,
    domain   varchar2(100 byte) not null enable,
    kontext  varchar2(30 byte) not null enable,
    sprache  varchar2(10 byte) not null enable,
    key      varchar2(255 byte) not null enable,
    pos      number(*, 0),
    singular varchar2(255 byte),
    plural   varchar2(255 byte),
    status   varchar2(3 byte)
);

alter table enum
    add constraint enum_pk primary key ( id )
        using index enable;

alter table enum flashback archive mongo


